#include<bits/stdc++.h>
using namespace std;
int n,m;
long long s;
int w[200005],v[200005];
int l[200005],r[200005];
long long num[200005]={0},num2[200005]={0};
long long solve(int ww){

    long long ans=0;
    for(int i=1;i<=n;i++){
        num[i]=num[i-1]+int(w[i]>=ww);
    }
    for(int i=1;i<=n;i++){
        num2[i]=num2[i-1]+int(w[i]>=ww)*v[i];
    }
    for(int i=1;i<=m;i++){
        ans+=(num[r[i]]-num[l[i]-1])*(num2[r[i]]-num2[l[i]-1]);
    }
    return ans;
}
int main(){
    cin>>n>>m>>s;

    for(int i=1;i<=n;i++) cin>>w[i]>>v[i];
    for(int i=1;i<=m;i++) cin>>l[i]>>r[i];

    long long ll=1;
    long long rr=1e18;
    long long ans=1e18;
    while (ll <= rr) {
	        long long mid = (ll + rr) / 2;
	        long long y = solve(mid);
	        ans = min(ans, llabs(y - s));

	        if (y > s) {
	            ll = mid + 1;
	        } else {
	            rr = mid - 1;
	        }
	    }

    cout<<ans<<"\n";
    return 0;
}
